import { scope, type Module } from "arktype";

// A single scope({...}) call that defines all four dot-namespaced aliases.
//
// The trick: pass sub-modules as values under the namespace keys ("db", "api").
// ArkType will expose them as nested BoundModules on the exported Module, and
// it will also resolve cross-namespace string references like "db.User" when
// the api.* types are being parsed.

const schemaScope = scope({
  // ── db namespace ────────────────────────────────────────────────────────
  "db.User": {
    id: "string.uuid",
    "name": "1<=string<=50",
    orgId: "string.uuid",
  },
  "db.Org": {
    id: "string.uuid",
    "name": "1<=string<=100",
  },

  // ── api namespace ────────────────────────────────────────────────────────
  // api.* types reference db.* by string alias, not by inlining the shapes.
  "api.CreateUserRequest": {
    user: "db.User",
    "token": "32<=string<=256",
  },
  "api.CreateOrgRequest": {
    org: "db.Org",
    adminUserId: "string.uuid",
  },
});

// Export the module so consumers can do:
//   import { schemaModule } from "./schema.js"
//   schemaModule.db.User       ← Type<{ id: string; name: string; orgId: string }>
//   schemaModule.api.CreateUserRequest  ← Type<{ user: ...; token: string }>
export const schemaModule = schemaScope.export();

export type SchemaModule = typeof schemaModule;

